function validateEnvironmentVariables(config) {
  const regex = /env_(.*?)=(.*)/g;
  let match;
  while ((match = regex.exec(config)) !== null) {
    const variable = match[1];
    const pattern = new RegExp(`env_${variable}=([^#\n]+)`);
    if (!pattern.test(config)) {
      return false;
    }
  }
  return true;
}

