class Solution:
  def validate_environment_variables(self, config):
    regex = re.compile(r'env_(.*?)=(.*)')
    match = regex.search(config)
    while match:
      variable = match.group(1)
      pattern = re.compile(f'env_{variable}=[^#\n]+')
      if not pattern.search(config):
        return False
      match = regex.search(config, match.end())
    return True
